// Toma la respuesta de get_brand_contract y construye el brand_contract
// en el mismo formato que el pipeline espera.
// Si el RPC retornó NULL (marca sin contrato), usa un contrato genérico.

const rpcResult = $input.first().json;
const prevItem = $('Obtener brand_contract por slug').first().json;

// Detectar si el RPC falló o devolvió null
const contractData = (rpcResult && typeof rpcResult === 'object' && rpcResult.brand_slug)
  ? rpcResult
  : null;

const brand_slug = contractData && contractData.brand_slug
  || ($('Nodo anterior del flujo').first().json.db_record && $('Nodo anterior del flujo').first().json.db_record.brand_slug)
  || 'desconocido';

// Contrato genérico de fallback (cuando la marca no tiene definición en brand_contracts)
const genericContract = {
  brand_slug,
  brand_name: brand_slug,
  language: 'pt',
  market: 'pt-BR',
  branded_products: [],
  forbidden_competitors: [
    'Blaze', 'Stake', 'Betano', '1xBet', 'F12Bet', 'KTO',
    'Estrela Bet', 'Pixbet', 'Sportingbet', 'Superbet',
    'Novibet', 'BetMGM', 'BetBoom', 'bet365', 'Betnacional', 'Aposta Ganha'
  ],
  writing_rules: [
    'Nunca mencionar concorrentes',
    'Mínimo 2 menções à marca por artigo'
  ],
  contract_version: 'generic-fallback',
  _warning: 'Marca sem brand_contract definido em brand_contracts. Contrato genérico aplicado.'
};

const brand_contract = contractData || genericContract;

// Inyectar en el item del flujo preservando todos los campos anteriores
const anteriorItem = $('Nodo anterior del flujo').first().json;
return [{
  json: {
    ...anteriorItem,
    brief_final: {
      ...(anteriorItem.brief_final || {}),
      brand_contract  // sobreescribe el brand_contract con el correcto
    }
  }
}];
